(function () {
  function normalize(value) {
    return String(value || '').toLowerCase();
  }

  function render(items) {
    var root = document.getElementById('search-results');
    var hint = document.getElementById('search-hint');
    if (!root || !hint) {
      return;
    }
    hint.textContent = items.length ? '为你找到相关影片' : '没有找到匹配影片';
    root.innerHTML = items.slice(0, 240).map(function (movie) {
      return '<article class="movie-card">' +
        '<a href="' + movie.file + '" class="movie-card-link">' +
        '<div class="movie-poster"><img src="' + movie.cover + '" alt="' + movie.title.replace(/"/g, '&quot;') + '" loading="lazy"><span class="movie-duration">' + movie.rating + '</span><span class="play-mark">▶</span></div>' +
        '<div class="movie-card-body"><h3>' + movie.title + '</h3><p>' + movie.summary + '</p><div class="movie-meta-row"><span>' + movie.year + '</span><span>' + movie.type + '</span><span>' + movie.region + '</span></div></div>' +
        '</a></article>';
    }).join('');
  }

  function search() {
    var input = document.getElementById('search-page-input');
    var type = document.getElementById('search-page-type');
    var query = normalize(input ? input.value : '').trim();
    var selectedType = type ? type.value : '';
    var items = SEARCH_MOVIES.filter(function (movie) {
      var haystack = normalize([movie.title, movie.year, movie.region, movie.type, movie.genre, movie.tags.join(' '), movie.summary].join(' '));
      var matchesQuery = !query || haystack.indexOf(query) !== -1;
      var matchesType = !selectedType || movie.type === selectedType;
      return matchesQuery && matchesType;
    });
    render(items);
  }

  document.addEventListener('DOMContentLoaded', function () {
    var params = new URLSearchParams(window.location.search);
    var input = document.getElementById('search-page-input');
    var type = document.getElementById('search-page-type');
    if (input && params.get('q')) {
      input.value = params.get('q');
    }
    if (input) {
      input.addEventListener('input', search);
    }
    if (type) {
      type.addEventListener('change', search);
    }
    search();
  });
})();
